import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const isStaff = user?.userType === 'user';

  const navItems = [
    { path:'/dashboard',        label:'Dashboard',       show:true },
    { path:'/books',            label:'Books',            show:true },
    { path:'/members',          label:'Members',          show:isStaff },
    { path:'/requests',         label:'Borrow Requests',  show:isStaff },
    { path:'/borrows',          label:'Borrows',          show:isStaff },
    { path:'/categories',       label:'Categories',       show:true },
    { path:'/create-assistant', label:'Add Assistant',    show:user?.role==='librarian' },
    { path:'/my-borrows',       label:'My Library',       show:!isStaff },
  ];

  const roleLabel:any = { librarian:'Librarian', library_assistant:'Library Assistant', student:'Student', staff:'Staff Member' };
  const roleColor:any = { librarian:'#c9a84c', library_assistant:'#10b981', student:'#60a5fa', staff:'#a78bfa' };
  const rc = roleColor[user?.role||''] || '#c9a84c';

  return (
    <>
      <style>{`
        .nav-lnk {
          display:flex; align-items:center; padding:10px 16px;
          border-radius:10px; font-size:14px; font-weight:500;
          color:rgba(255,255,255,0.4); text-decoration:none;
          margin-bottom:2px; transition:all .18s; position:relative;
        }
        .nav-lnk::before {
          content:''; position:absolute; left:0; top:20%; bottom:20%;
          width:3px; background:#c9a84c; border-radius:0 3px 3px 0;
          opacity:0; transform:scaleY(0); transition:all .18s;
        }
        .nav-lnk:hover { color:rgba(255,255,255,0.8); background:rgba(255,255,255,0.05); }
        .nav-lnk.active { color:#fff !important; background:rgba(201,168,76,0.12) !important; font-weight:700 !important; }
        .nav-lnk.active::before { opacity:1; transform:scaleY(1); }
        .signout-btn { transition:all .18s !important; }
        .signout-btn:hover { color:#f87171 !important; background:rgba(239,68,68,0.08) !important; border-color:rgba(239,68,68,0.15) !important; }
      `}</style>

      <aside style={{
        width:240, minHeight:'100vh',
        background:'linear-gradient(180deg, #090918 0%, #0b0b1e 100%)',
        borderRight:'1px solid rgba(255,255,255,0.05)',
        display:'flex', flexDirection:'column', flexShrink:0,
      }}>
        {/* Top glow */}
        <div style={{position:'absolute',top:0,left:0,width:240,height:160,background:'radial-gradient(ellipse at top left,rgba(201,168,76,0.07),transparent 70%)',pointerEvents:'none'}}/>

        {/* Logo */}
        <div style={{padding:'30px 20px 24px',borderBottom:'1px solid rgba(255,255,255,0.05)'}}>
          <div style={{fontFamily:"'Playfair Display',serif",fontSize:22,fontWeight:700,color:'#fff',letterSpacing:'-0.5px'}}>
            LibraryMS
          </div>
          <div style={{fontSize:10,color:'rgba(201,168,76,0.5)',letterSpacing:'2px',textTransform:'uppercase',marginTop:4,fontWeight:600}}>
            BAUST · University Library
          </div>
          <div style={{marginTop:16,height:1,background:'linear-gradient(90deg,rgba(201,168,76,0.35),rgba(201,168,76,0.0))'}}/>
        </div>

        {/* Nav */}
        <nav style={{flex:1,padding:'20px 12px',overflowY:'auto'}}>
          <div style={{fontSize:10,fontWeight:700,color:'rgba(255,255,255,0.15)',letterSpacing:'2px',textTransform:'uppercase',padding:'0 6px',marginBottom:12}}>
            Navigation
          </div>
          {navItems.filter(i=>i.show).map(item=>(
            <NavLink key={item.path} to={item.path}
              className={({isActive})=>`nav-lnk${isActive?' active':''}`}>
              {item.label}
            </NavLink>
          ))}
        </nav>

        {/* User */}
        <div style={{padding:'12px 14px 22px',borderTop:'1px solid rgba(255,255,255,0.05)'}}>
          <div style={{background:'rgba(255,255,255,0.03)',border:'1px solid rgba(255,255,255,0.06)',borderRadius:13,padding:'14px',marginBottom:8}}>
            <div style={{display:'flex',alignItems:'center',gap:11,marginBottom:user?.member_id?10:0}}>
              <div style={{width:38,height:38,borderRadius:'50%',
                background:`linear-gradient(135deg,${rc},${rc}66)`,
                border:`2px solid ${rc}44`,
                display:'flex',alignItems:'center',justifyContent:'center',
                fontWeight:800,color:'#fff',fontSize:16,flexShrink:0,
                boxShadow:`0 0 16px ${rc}30`
              }}>
                {user?.name?.charAt(0).toUpperCase()}
              </div>
              <div style={{minWidth:0,flex:1}}>
                <div style={{fontSize:14,fontWeight:700,color:'#fff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{user?.name}</div>
                <div style={{fontSize:11,color:rc,marginTop:2,fontWeight:600}}>{roleLabel[user?.role||'']||user?.role}</div>
              </div>
            </div>
            {user?.member_id && (
              <div style={{background:'rgba(0,0,0,0.25)',borderRadius:7,padding:'5px 10px',display:'flex',alignItems:'center',gap:6}}>
                <span style={{fontSize:10,color:'rgba(255,255,255,0.2)',fontWeight:700,letterSpacing:'1px',textTransform:'uppercase'}}>ID</span>
                <span style={{fontSize:12,color:'rgba(255,255,255,0.45)',fontFamily:'monospace',fontWeight:600}}>{user.member_id}</span>
              </div>
            )}
          </div>

          <button className="signout-btn"
            onClick={()=>{ logout(); navigate('/login'); }}
            style={{width:'100%',display:'flex',alignItems:'center',justifyContent:'center',gap:8,padding:'10px',borderRadius:10,fontSize:13,fontWeight:600,color:'rgba(255,255,255,0.28)',background:'transparent',border:'1px solid rgba(255,255,255,0.06)',cursor:'pointer',fontFamily:'inherit',transition:'all .18s'}}>
            ⎋ Sign Out
          </button>
        </div>
      </aside>
    </>
  );
}
